    42→    ({
    43→      closable,
    44→      message,
    45→      onClose,
    46→      progress,
    47→      shouldTimeout,
    48→      timeout,
    49→      title,
    50→      variant,
    51→    }: ToastParams) => {
    52→      let toastTimeout = null;
    53→      if (timeout !== undefined) {
    54→        toastTimeout = timeout;
    55→      } else if (shouldTimeout) {
